import React, { useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { Menu, X, ShoppingCart, Heart, Package, User } from 'lucide-react';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { useWishlist } from '../context/WishlistContext';

const Navbar = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { getCartCount } = useCart();
  const { user, logout } = useAuth();
  const { count: wishCount } = useWishlist();
  const [menuOpen, setMenuOpen] = useState(false);

  const handleLogout = async () => {
    await logout();
    navigate('/');
  };

  const isActive = (path) => location.pathname === path;

  return (
    <nav className="navbar" role="navigation" aria-label="Main navigation">
      <div className="nav-inner">
        <Link to="/" className="nav-logo" aria-label="Nova Shop Home">
          Nova<span>.</span>
        </Link>
        <ul className={`nav-links ${menuOpen ? 'open' : ''}`} id="navLinks">
          <li>
            <Link to="/" className={isActive('/') ? 'active' : ''} onClick={() => setMenuOpen(false)}>
              Home
            </Link>
          </li>
          <li>
            <Link
              to="/products"
              className={isActive('/products') ? 'active' : ''}
              onClick={() => setMenuOpen(false)}
            >
              Shop
            </Link>
          </li>
          {user && (
            <li>
              <Link
                to="/orders"
                className={isActive('/orders') ? 'active' : ''}
                onClick={() => setMenuOpen(false)}
              >
                <Package size={16} style={{ verticalAlign: 'middle', marginRight: 4 }} />
                Orders
              </Link>
            </li>
          )}
          <li>
            <Link
              to="/wishlist"
              className={isActive('/wishlist') ? 'active' : ''}
              onClick={() => setMenuOpen(false)}
            >
              <Heart size={16} style={{ verticalAlign: 'middle', marginRight: 4 }} />
              Wishlist
              {user && wishCount > 0 && <span className="nav-pill">{wishCount}</span>}
            </Link>
          </li>
          <li>
            <Link
              to="/login"
              className={isActive('/login') ? 'active' : ''}
              onClick={() => setMenuOpen(false)}
            >
              <User size={16} style={{ verticalAlign: 'middle', marginRight: 4 }} />
              {user ? 'Account' : 'Sign in'}
            </Link>
          </li>
        </ul>
        <div className="nav-actions">
          <Link to="/cart" className="nav-cart-link" aria-label="Shopping cart">
            <ShoppingCart size={22} strokeWidth={1.75} />
            <span className={`cart-count ${getCartCount() > 0 ? '' : 'hidden'}`} aria-live="polite">
              {getCartCount()}
            </span>
          </Link>
          {user ? (
            <div className="nav-user">
              <span className="nav-user-name">Hi, {user.name?.split(' ')[0] || 'there'}</span>
              <button type="button" className="btn btn-outline btn-sm" onClick={handleLogout}>
                Log out
              </button>
            </div>
          ) : (
            <Link to="/login" className="btn btn-primary btn-sm">
              Sign in
            </Link>
          )}
          <button
            type="button"
            className="hamburger"
            id="hamburger"
            aria-label={menuOpen ? 'Close menu' : 'Open menu'}
            aria-expanded={menuOpen}
            onClick={() => setMenuOpen(!menuOpen)}
          >
            {menuOpen ? <X size={22} /> : <Menu size={22} />}
          </button>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
